          r'''SELECT p.id, p.name, p.status, p.score, p.avatar, pr.id AS profile__id, pr.person_id AS profile__person_id, pr.nickname AS profile__nickname, pr.created_at AS profile__created_at, pr.visit_count AS profile__visit_count, pr.confidence AS profile__confidence, pr.metadata_json AS profile__metadata_json, pr.payload AS profile__payload FROM person p LEFT JOIN person_profile pr ON pr.person_id = p.id WHERE p.id = ?''',
          (row) => PersonWithProfileRow(
            id: row.readInt(0),
            name: row.readString(1),
            status:
                _db.adapters.sqlValueToPersonStatus(row.readString(2))
                    as String,
            score: row.readNullableDouble(3),
            avatar: row.readNullableBlob(4),
            profile:
                (row.readValue(5) == null &&
                    row.readValue(6) == null &&
                    row.readValue(7) == null &&
                    row.readValue(8) == null &&
                    row.readValue(9) == null &&
                    row.readValue(10) == null &&
                    row.readValue(11) == null &&
                    row.readValue(12) == null
                ? null
                : ProfileRow(
                    id: row.readInt(5),
                    personId: row.readInt(6),
                    displayName: row.readString(7),
                    createdAt:
                        _db.adapters.sqlValueToPersonProfileCreatedAt(
                              row.readString(8),
                            )
                            as DateTime,
                    visitCount:
                        _db.adapters.sqlValueToPersonProfileVisitCount(
                              row.readInt(9),
                            )
                            as int,
                    confidence:
                        _db.adapters.sqlValueToPersonProfileConfidence(
                              row.readNullableDouble(10),
                            )
                            as double?,
                    metadataJson:
                        _db.adapters.sqlValueToPersonProfileMetadataJson(
                              row.readNullableString(11),
                            )
                            as String?,
                    payload:
                        _db.adapters.sqlValueToPersonProfilePayload(
                              row.readBlob(12),
                            )
                            as Uint8List,
                  )),
          ),
          parameters: [params.id],
        );
      },
    );
  }

  Future<void> updateName(PersonUpdateNameParams params) async {
    await _db.connection.execute(
      r'''UPDATE person SET name = ? WHERE id = ?''',
      parameters: [params.name, params.id],
      affectedTables: const <String>{'person'},
    );
  }
}

final class ProfileQueries {
  ProfileQueries(this._db);

  final DartDb _db;

  Future<void> insertOne(ProfileInsertOneParams params) async {
    await _db.connection.execute(
      r'''INSERT INTO person_profile (id, person_id, nickname, created_at, visit_count, confidence, metadata_json, payload) VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
      parameters: [
        params.id,
        params.personId,
        params.displayName,
        _db.adapters.personProfileCreatedAtToSql(params.createdAt),
        _db.adapters.personProfileVisitCountToSql(params.visitCount),
        _db.adapters.personProfileConfidenceToSql(params.confidence),
        _db.adapters.personProfileMetadataJsonToSql(params.metadataJson),
        _db.adapters.personProfilePayloadToSql(params.payload),
      ],
      affectedTables: const <String>{'person_profile'},
    );
  }

  SelectRunner<ProfileRow> selectAll() {
    return SelectRunner<ProfileRow>(
      database: _db.runtimeDatabase,
      affectedTables: const <String>{'person_profile'},
      query: () {
        return _db.connection.select(
          r'''SELECT id, person_id, nickname, created_at, visit_count, confidence, metadata_json, payload FROM person_profile ORDER BY id''',
          (row) => ProfileRow(
            id: row.readInt(0),
            personId: row.readInt(1),
            displayName: row.readString(2),
            createdAt:
                _db.adapters.sqlValueToPersonProfileCreatedAt(row.readString(3))
                    as DateTime,
            visitCount:
                _db.adapters.sqlValueToPersonProfileVisitCount(row.readInt(4))
                    as int,
            confidence:
                _db.adapters.sqlValueToPersonProfileConfidence(
                      row.readNullableDouble(5),
                    )
                    as double?,
            metadataJson:
                _db.adapters.sqlValueToPersonProfileMetadataJson(
                      row.readNullableString(6),
                    )
                    as String?,
            payload:
                _db.adapters.sqlValueToPersonProfilePayload(row.readBlob(7))
                    as Uint8List,
          ),
        );
      },
    );
  }
}
